+/**
+ * Lighting system with torch glow and flickering embers.
+ * Implements radial gradient light sources for torches,
+ * darkens room corners, highlights characters near torches,
+ * and uses composite operations for blending.
+ */
+
+import { getRoomDimensions, getTorches, getCharacters } from './gameState';
+
+const LIGHT_RADIUS = 150;
+const EMBER_PARTICLE_COUNT = 15;
+const EMBER_LIFETIME = 1000; // ms
+
+class EmberParticle {
+  constructor(x, y) {
+    this.x = x;
+    this.y = y;
+    this.vx = (Math.random() - 0.5) * 0.3;
+    this.vy = -Math.random() * 0.5 - 0.2;
+    this.alpha = 1;
+    this.size = Math.random() * 1.5 + 0.5;
+    this.life = EMBER_LIFETIME;
+  }
+
+  update(delta) {
+    this.x += this.vx * delta;
+    this.y += this.vy * delta;
+    this.life -= delta;
+    this.alpha = Math.max(0, this.life / EMBER_LIFETIME);
+  }
+
+  isDead() {
+    return this.life <= 0;
+  }
+}
+
+class TorchLight {
+  constructor(x, y) {
+    this.x = x;
+    this.y = y;
+    this.particles = [];
+    this.flickerTime = 0;
+    this.flickerIntensity = 1;
+  }
+
+  update(delta) {
+    // Flicker intensity oscillates between 0.85 and 1.15 roughly 4 times per second
+    this.flickerTime += delta;
+    this.flickerIntensity = 1 + 0.15 * Math.sin(this.flickerTime * 0.025);
+
+    // Update particles
+    this.particles = this.particles.filter(p => !p.isDead());
+    if (this.particles.length < EMBER_PARTICLE_COUNT) {
+      // Spawn new ember near torch base with some randomness
+      const px = this.x + (Math.random() - 0.5) * 10;
+      const py = this.y + (Math.random() - 0.5) * 10;
+      this.particles.push(new EmberParticle(px, py));
+    }
+    this.particles.forEach(p => p.update(delta));
+  }
+
+  draw(ctx) {
+    // Draw radial gradient light
+    const gradient = ctx.createRadialGradient(
+      this.x, this.y, LIGHT_RADIUS * 0.1,
+      this.x, this.y, LIGHT_RADIUS
+    );
+    // Warm torch colors with flicker intensity
+    gradient.addColorStop(0, `rgba(255, 180, 100, ${0.6 * this.flickerIntensity})`);
+    gradient.addColorStop(0.5, `rgba(255, 140, 60, ${0.3 * this.flickerIntensity})`);
+    gradient.addColorStop(1, 'rgba(0,0,0,0)');
+
+    ctx.save();
+    ctx.globalCompositeOperation = 'lighter';
+    ctx.fillStyle = gradient;
+    ctx.beginPath();
+    ctx.arc(this.x, this.y, LIGHT_RADIUS, 0, Math.PI * 2);
+    ctx.fill();
+
+    // Draw ember particles
+    this.particles.forEach(p => {
+      const emberGradient = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.size * 4);
+      emberGradient.addColorStop(0, `rgba(255, 200, 120, ${p.alpha})`);
+      emberGradient.addColorStop(1, 'rgba(255, 200, 120, 0)');
+      ctx.fillStyle = emberGradient;
+      ctx.beginPath();
+      ctx.arc(p.x, p.y, p.size * 4, 0, Math.PI * 2);
+      ctx.fill();
+    });
+    ctx.restore();
+  }
+}
+
+export class LightingSystem {
+  constructor(canvas) {
+    this.canvas = canvas;
+    this.ctx = canvas.getContext('2d');
+    this.torches = [];
+    this.lastTime = performance.now();
+  }
+
+  init() {
+    // Initialize torch lights from game state torches
+    const torchData = getTorches();
+    this.torches = torchData.map(t => new TorchLight(t.x, t.y));
+  }
+
+  update() {
+    const now = performance.now();
+    const delta = now - this.lastTime;
+    this.lastTime = now;
+
+    this.torches.forEach(t => t.update(delta));
+  }
+
+  draw() {
+    const ctx = this.ctx;
+    const { width, height } = this.canvas;
+
+    // Clear canvas
+    ctx.clearRect(0, 0, width, height);
+
+    // Draw room base darkness (dark corners)
+    const room = getRoomDimensions();
+    const cornerGradient = ctx.createRadialGradient(
+      0, 0, 0,
+      room.width / 2, room.height / 2, Math.max(room.width, room.height)
+    );
+    cornerGradient.addColorStop(0, 'rgba(0,0,0,0.6)');
+    cornerGradient.addColorStop(1, 'rgba(0,0,0,0.95)');
+    ctx.fillStyle = cornerGradient;
+    ctx.fillRect(0, 0, width, height);
+
+    // Composite operation for light blending
+    ctx.globalCompositeOperation = 'lighter';
+
+    // Draw torch lights
+    this.torches.forEach(t => t.draw(ctx));
+
+    // Reset composite operation
+    ctx.globalCompositeOperation = 'source-over';
+
+    // Highlight characters near torches
+    const characters = getCharacters();
+    characters.forEach(char => {
+      // Check distance to nearest torch
+      let nearTorch = false;
+      for (const torch of this.torches) {
+        const dx = char.x - torch.x;
+        const dy = char.y - torch.y;
+        const dist = Math.sqrt(dx * dx + dy * dy);
+        if (dist < LIGHT_RADIUS * 0.6) {
+          nearTorch = true;
+          break;
+        }
+      }
+      if (nearTorch) {
+        // Draw subtle highlight glow around character
+        ctx.save();
+        ctx.shadowColor = 'rgba(255, 180, 100, 0.6)';
+        ctx.shadowBlur = 15;
+        ctx.fillStyle = 'rgba(255, 220, 150, 0.3)';
+        ctx.beginPath();
+        ctx.arc(char.x, char.y, char.radius + 10, 0, Math.PI * 2);
+        ctx.fill();
+        ctx.restore();
+      }
+    });
+  }
+}
